let text = $json.text.trim();

// Remove ```json and ```
text = text.replace(/^```json\s*/i, "");
text = text.replace(/^```\s*/i, "");
text = text.replace(/\s*```$/, "");

const cv = JSON.parse(text);

const geoId = "106395874";

const candidate = {
  skills: cv.skills || [],
  experience: cv.experience || [],
  education: cv.education || [],
  projects: cv.projects || [],
  languages: cv.languages || []
};

return cv.preferred_job_titles.map(title => ({
  json: {
    keyword: title,
    url: `https://www.linkedin.com/jobs/search/?keywords=${encodeURIComponent(title)}&geoId=${geoId}&f_TPR=r604800&f_WT=1%2C2%2C3&sortBy=DD`,
    candidate
  }
}));

return items.map(item => {
  let text = item.json.text.trim();

  text = text
    .replace(/^```(?:json)?/i, "")
    .replace(/```$/i, "")
    .trim();

  return {
    json: JSON.parse(text)
  };
});

return items.map(item => ({
  json: {
    title: item.json.title,
    company: item.json.companyName,
    location: item.json.location,
    link: item.json.link,
    description: item.json.descriptionText
  }
}));

